const body = $input.first().json.body || $input.first().json;
const required = ['client_name','engagement_name','authorized_targets','testing_window_start','testing_window_end'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) return [{ json: { valid: false, missing, body } }];
if (!Array.isArray(body.authorized_targets) || body.authorized_targets.length === 0)
  return [{ json: { valid: false, missing: ['authorized_targets must be non-empty array'], body } }];
return [{ json: { valid: true, body } }];

const client = $('Upsert Client').first().json;
const body = $('Validate Fields').first().json.body;
const prohibitedJson = JSON.stringify(body.prohibited_actions || []).replace(/'/g, "''");
return [{ json: {
  client_id: client.id,
  engagement_name: body.engagement_name,
  type: body.type || 'web_app',
  testing_window_start: body.testing_window_start,
  testing_window_end: body.testing_window_end,
  rate_limit_profile: body.rate_limit_profile || 'standard',
  prohibited_actions: prohibitedJson,
  roe_document_url: body.roe_document_url || null,
  evidence_handling_notes: body.evidence_handling_notes || null,
  emergency_contact: (body.contacts || [])[0]?.email || '',
  authorized_targets: body.authorized_targets
} }];

const engId = $('Insert Engagement').first().json.id;
const targets = $('Prepare Engagement').first().json.authorized_targets;
const rows = targets.map(t =>
  `('${engId}', '${t.value.replace(/'/g,"''")}', '${t.scope_type}', true, '${(t.notes||'').replace(/'/g,"''")}')`
).join(',\n');
return [{ json: { engagement_id: engId, insert_sql: rows } }];

